INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('heelevel3-6f0ba476-moex-00182', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-113-9bdab6d6', 'sub-heelevel3-6f0ba476-03', NULL, 'single_choice', '依稅捐稽徵法及相關稅法規定，下列案件稽徵機關可採公告方式代替核定稅額通知書之填具及送 達，何者敘述錯誤？', '["綜合所得稅結算申報，經查核依申報應退稅款辦理退稅之案件", "所得稅法第14條之7第3項規定之個人房屋土地交易所得稅，調查結果之核定通知書送達及 查對更正之案件", "稽徵機關核定加值型及非加值型營業稅，其無應補繳稅額或無應退稅額者之案件", "營利事業所得稅結算申報，適用所得稅法第 39 條盈虧互抵且按申報數核定無應補或應退稅款 之案件"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:29+00:00", "source_pdf_sha1": "c6b009846a0f", "answer_pdf_sha1": "2b16534b8efc", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "318", "s": "0803", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('heelevel3-6f0ba476-moex-00183', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-113-9bdab6d6', 'sub-heelevel3-6f0ba476-03', NULL, 'single_choice', '依現行所得稅法規定，我國境內居住者或境內法人投資境內外公司所獲得之各類所得如何課稅之 敘述，下列何者正確？', '["總機構在境內法人股東，投資國外公司所分配之股利，全額計入營利事業所得額，其境外所納 稅額可全額扣抵境內應納稅額", "總機構在境內法人股東，投資國內公司所分配之股利，全額不計入營利事業所得額，但須計入 基本所得額", "境內個人居住者股東，投資國內公司所分配之股利併入綜合所得總額計算稅額者，有8.5%可抵 減稅額，抵減綜合所得稅額，每戶抵減上限8萬元", "境內個人居住者股東，投資境外基金獲配之利息，全額計入個人基本所得額"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:29+00:00", "source_pdf_sha1": "c6b009846a0f", "answer_pdf_sha1": "2b16534b8efc", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "318", "s": "0803", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('heelevel3-6f0ba476-moex-00184', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-113-9bdab6d6', 'sub-heelevel3-6f0ba476-03', NULL, 'single_choice', '甲公司（帳上無累積虧損）113年5月1日至5月31日營利事業所得稅之計算與申報規定，下列 敘述何者錯誤？', '["甲公司應申報112年度營利事業所得稅及111年度未分配盈餘加徵5%營利事業所得稅", "計算甲公司111年度未分配盈餘，係以營利事業當年度依商業會計法或其他法律有關編製財務 報告規定處理之本期稅後淨利，加計本期稅後淨利以外純益項目，可減除當年度盈餘分配之股 利或盈餘及當年度盈餘提列之法定盈餘公積", "甲公司當年度如有符合產業創新條例第 23 條之 3 規定以盈餘進行實質投資者，該投資金額得 列為未分配盈餘之減項", "營利事業依規定計算的未分配盈餘為零或負數者，無須辦理申報"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:29+00:00", "source_pdf_sha1": "c6b009846a0f", "answer_pdf_sha1": "2b16534b8efc", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "318", "s": "0803", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('heelevel3-6f0ba476-moex-00185', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-113-9bdab6d6', 'sub-heelevel3-6f0ba476-03', NULL, 'single_choice', 'A公司為加值型營業稅之營業人，113年7月15日申報5-6月國內應稅銷售額為15,000萬元，免 稅銷售額4,000萬元，外銷銷售額為7,000萬元，因進貨及費用而取得之進項稅額為900萬元， 上期累積留抵税額50萬元，則該公司申報當期不得扣抵比例及營業稅為若干元？', '["當期不得扣抵比例15.4%，退稅金額200萬元", "當期不得扣抵比例15.4%，退稅金額61.4萬元", "當期不得扣抵比例15%，退稅金額65萬元", "當期不得扣抵比例15%，退稅金額200萬元"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:29+00:00", "source_pdf_sha1": "c6b009846a0f", "answer_pdf_sha1": "2b16534b8efc", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "318", "s": "0803", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('heelevel3-6f0ba476-moex-00186', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-113-9bdab6d6', 'sub-heelevel3-6f0ba476-03', NULL, 'single_choice', 'A公司出租一棟大樓予B公司，113年5月1日訂定合約收取押金300,000元，並於每月月底收 取租金126,000元，假設A公司與B公司皆為依一般稅額計算之營業人，當年度1月1日郵政儲 金1年期定期固定利率為1.6%，則A公司6月底就出租該大樓部分應開立統一發票予B公司之 銷售額為若干？', '["381元", "400元", "120,381元", "120,400元"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:29+00:00", "source_pdf_sha1": "c6b009846a0f", "answer_pdf_sha1": "2b16534b8efc", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "318", "s": "0803", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('heelevel3-6f0ba476-moex-00187', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-113-9bdab6d6', 'sub-heelevel3-6f0ba476-03', NULL, 'single_choice', '依113年修正房屋稅條例規定，下列敘述何者錯誤？', '["以土地設定地上權之使用權房屋，向該使用權人徵收之", "供自住、公益出租人出租使用者，為其房屋現值百分之一點二。但本人、配偶及未成年子女於 全國僅持有一戶房屋，供自住且房屋現值在一定金額以下者，為其房屋現值百分之一", "房屋遇有焚燬、坍塌、拆除至不堪居住程度者，應由納稅義務人申報當地主管稽徵機關查實後， 在未重建完成期內，停止課稅", "住家用房屋現值在新臺幣10萬元以下法人持有者，全國合計以3戶為限，免徵房屋稅"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:29+00:00", "source_pdf_sha1": "c6b009846a0f", "answer_pdf_sha1": "2b16534b8efc", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "318", "s": "0803", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('heelevel3-6f0ba476-moex-00188', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-113-9bdab6d6', 'sub-heelevel3-6f0ba476-03', NULL, 'single_choice', '有關房地合一稅之敘述，下列何者正確？', '["房地合一稅之稅率為差別比例稅率", "個人、配偶或子女設有戶籍、持有並居住於該房屋連續滿6年則可符合自住房地優惠", "若因財政部公告之調職、非自願離職或其他非自願性因素，交易持有期間在5年以下之房地者， 稅率為10%", "自110年7月1日起農地亦納入房地合一稅之課稅範圍"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:29+00:00", "source_pdf_sha1": "c6b009846a0f", "answer_pdf_sha1": "2b16534b8efc", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "318", "s": "0803", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('heelevel3-6f0ba476-moex-00189', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-113-9bdab6d6', 'sub-heelevel3-6f0ba476-03', NULL, 'single_choice', '中華民國居住之個人，有關綜合所得稅中各類所得之敘述，何者正確？', '["薪資收入可減除薪資所得特別扣除額及與提供勞務直接相關且由所得人負擔之必要費用", "境內發行公債、公司債獲配之利息所得採扣繳10%分離課稅", "境內證券交易所得屬於財產交易所得採扣繳10%分離課稅", "股利收入屬於營利所得，申報綜合所得稅一律採分開計稅合併申報"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:29+00:00", "source_pdf_sha1": "c6b009846a0f", "answer_pdf_sha1": "2b16534b8efc", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "318", "s": "0803", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('heelevel3-6f0ba476-moex-00190', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-113-9bdab6d6', 'sub-heelevel3-6f0ba476-03', NULL, 'single_choice', '依所得稅法規定，申報113年度綜合所得稅時，下列特別扣除額何者訂有排富條款？①儲蓄投資', '["幼兒學前特別扣除額", "長期照顧特別扣除額", "教育學費特別扣除額  ⑤房 屋租金支出特別扣除", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:29+00:00", "source_pdf_sha1": "c6b009846a0f", "answer_pdf_sha1": "2b16534b8efc", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "318", "s": "0803", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 23, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('heelevel3-6f0ba476-moex-00191', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-113-9bdab6d6', 'sub-heelevel3-6f0ba476-03', NULL, 'single_choice', '甲君112年8月出售自用住宅用地，申報移轉現值為107萬元，繳納土地增值稅8萬元，113年 6月重購自用住宅用地，取得時申報移轉現值為105萬元，甲君可申請退還之土地增值稅額為多 少元？', '["0萬元", "6萬元", "8萬元", "10萬元"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:29+00:00", "source_pdf_sha1": "c6b009846a0f", "answer_pdf_sha1": "2b16534b8efc", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "318", "s": "0803", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL)
